+///
 /// Uses volatile write to prevent the LTO optimizer from eliminating the store.
 #[inline]
 pub unsafe fn set_abi_errno(val: c_int) {
     // Set our internal errno.
     let p = unsafe { __errno_location() };
     unsafe { std::ptr::write_volatile(p, val) };
